        if (this.stateTimer <= 0) {
          this.pacMesh.scale.setScalar(1);
          if (this.lives <= 0) {
            this.endGame();
          } else {
            this.resetPositions();
            this.state = GameState.READY;
            this.stateTimer = READY_DURATION;
            this.onStateChange?.(this.state);
          }
        }
        break;

      case GameState.LEVEL_COMPLETE:
        this.stateTimer -= delta;
        if (this.stateTimer <= 0) {
