    if (this.dotStreakTimer > 0) {
      this.dotStreakTimer -= delta;
      if (this.dotStreakTimer <= 0) {
        this.resetDotStreak();
      }
    }

    // Siren level based on remaining dots
    this.updateSirenLevel();
  }

